// radar.ts — typed blip registry
export type Ring = 'adopt' | 'trial' | 'assess' | 'hold';
export type Quadrant = 'tooling-sdks' | 'integrations-patterns';
export type Movement = 'new' | 'moved-in' | 'moved-out' | 'no-change';

export interface Blip {
  id: string;
  name: string;
  quadrant: Quadrant;
  ring: Ring;
  movement: Movement;
  movedFrom?: Ring;
  lastReviewedDate: string;   // ISO date
  synopsis: string;           // ≤ 2 sentences shown on hover
  rationale: string;          // Full evidence-based justification
  howToUse?: string;          // For adopt/trial
  watchFor?: string;          // For assess/hold
  references: string[];
}

// radar-data.ts — current edition
export const BLIPS: Blip[] = [
  {
    id: 'anthropic-python-sdk',
    name: 'Anthropic Python SDK',
    quadrant: 'tooling-sdks',
    ring: 'adopt',
    movement: 'no-change',
    lastReviewedDate: '2025-07-01',
    synopsis: 'Official Python client for Claude. Stable, typed, actively maintained.',
    rationale: 'Used in production across all platform teams since Q1 2024. No breaking changes in four minor versions. 94% engineer satisfaction in last survey.',
    howToUse: 'Pin to ^0.x.x. Use AsyncAnthropic in async contexts. Enable sdk-native retries (max_retries=3).',
    references: ['https://docs.anthropic.com/sdk-reference', 'internal:RFC-2041'],
  },
  {
    id: 'claude-code',
    name: 'Claude Code',
    quadrant: 'tooling-sdks',
    ring: 'trial',
    movement: 'moved-in',
    movedFrom: 'assess',
    lastReviewedDate: '2025-07-01',
    synopsis: 'AI coding assistant with agentic capabilities. Moved to Trial after successful pilot.',
    rationale: 'Pilot with 4 teams over 8 weeks showed 22% reduction in PR review cycle time. Evaluate before use in automated pipelines.',
    watchFor: undefined,
    howToUse: 'Enable per-team with explicit scope configuration. Do not use in unattended CI pipelines without human review step.',
    references: ['internal:pilot-report-2025-Q2'],
  },
  {
    id: 'unconstrained-agents',
    name: 'Unconstrained Agentic Loops',
    quadrant: 'integrations-patterns',
    ring: 'hold',
    movement: 'no-change',
    lastReviewedDate: '2025-07-01',
    synopsis: 'Agents without HITL gates or iteration limits. Security risk confirmed in Q3 2024 incident.',
    rationale: 'Post-mortem PM-2024-Q3-001: unconstrained loop sent 847 emails before detection. TC-TA-01 confirms mandatory HITL gate requirement.',
    watchFor: 'Re-evaluate when Anthropic ships model-level tool limits and internal HITL gate framework reaches v1.0 (target Q2 2026).',
    references: ['internal:PM-2024-Q3-001', 'internal:TC-TA-01', 'internal:RFC-2089'],
  },
];

// Validate: every hold blip must have a watchFor
export function validateRadar(blips: Blip[]): string[] {
  const errors: string[] = [];
  for (const b of blips) {
    if (b.ring === 'hold' && !b.watchFor) {
      errors.push(\`\${b.id}: Hold blip missing watchFor condition\`);
    }
    if ((b.ring === 'adopt' || b.ring === 'trial') && !b.howToUse) {
      errors.push(\`\${b.id}: Adopt/Trial blip missing howToUse guidance\`);
    }
    if (b.movement === 'moved-in' && !b.movedFrom) {
      errors.push(\`\${b.id}: moved-in blip missing movedFrom field\`);
    }
  }
  return errors;
}

// GitHub Actions step: radar compliance check
// .github/workflows/architecture-review.yml

// Pseudo-workflow triggered on PR to main:
// 1. Parse PR description and linked RFC for tool names
// 2. Look up each mentioned tool in the radar data
// 3. Fail the check if any tool is in Hold without an approved exception

import { BLIPS } from './radar-data';

function checkRfcRadarCompliance(rfcText: string): {
  violations: string[];
  warnings: string[];
} {
  const violations: string[] = [];
  const warnings: string[] = [];

  for (const blip of BLIPS) {
    if (!rfcText.toLowerCase().includes(blip.name.toLowerCase())) continue;

    if (blip.ring === 'hold') {
      violations.push(
        \`\${blip.name} is in HOLD ring. \n\` +
        \`Reason: \${blip.rationale.slice(0, 100)}... \n\` +
        \`To proceed, request an architecture board exception.\`
      );
    } else if (blip.ring === 'assess') {
      warnings.push(
        \`\${blip.name} is in ASSESS ring — not yet approved for production. \n\` +
        \`Watch for: \${blip.watchFor ?? 'see radar for details'}\`
      );
    }
  }

  return { violations, warnings };
}
